@Entity data class Visit(val id: Long, val siteName: String, val timestamp: Long)
@Dao interface VisitDao {
    @Insert suspend fun insert(visit: Visit)
    @Query("SELECT * FROM Visit ORDER BY timestamp :sortOrder")
    fun getAllVisits(sortOrder: String): LiveData<List<Visit>>
}

class VisitRepository(
    private val dao: VisitDao,
    private val dataStore: DataStore<Preferences>
) {
    private val SORT_KEY = stringPreferencesKey("sort_order")

    val sortOrder: Flow<String> = dataStore.data.map { it[SORT_KEY] ?: "ASC" }

    suspend fun insert(visit: Visit) = dao.insert(visit)
    suspend fun setSortOrder(order: String) {
        dataStore.edit { it[SORT_KEY] = order }
    }

    fun getVisits(): LiveData<List<Visit>> {
        return sortOrder.flatMapLatest { order ->
            dao.getAllVisits(order)
        }.asLiveData()
    }
}

class VisitViewModel(
    private val repository: VisitRepository
) : ViewModel() {
    val visits: LiveData<List<Visit>> = repository.getVisits()
    val sortOrder: LiveData<String> = repository.sortOrder.asLiveData()

    fun addVisit(siteName: String) {
        viewModelScope.launch {
            val visit = Visit(
                id = System.currentTimeMillis(),
                siteName = siteName,
                timestamp = System.currentTimeMillis()
            )
            repository.insert(visit)
        }
    }

    fun toggleSort() {
        viewModelScope.launch {
            val current = sortOrder.value ?: "ASC"
            repository.setSortOrder(if (current == "ASC") "DESC" else "ASC")
        }
    }
}
```

## Data Flow

1. **Dialog Input** → ViewModel.addVisit() → Repository.insert() → Room DAO → Database
2. **Sort Toggle** → ViewModel.toggleSort() → Repository.setSortOrder() → DataStore → Triggers LiveData refresh
3. **List Display** → ViewModel.visits LiveData → UI observes → Automatic updates on data/sort changes
4. **Rotation** → DataStore preserves sort preference → LiveData maintains list state → UI restores seamlessly

